        code_template="from itertools import product\nfor length in range(1, 10):\n    for cmds in product([1,2], repeat=length):\n        x = 1\n        for c in cmds:\n            if c == 1: x += 2\n            else: x *= 3\n        if x == 9:\n            print(length)\n            exit()",
