    add(12, "\u0412\u0441\u0435 \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442\u044b", "\u0418\u0441\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c: +1, \xd72. \u041d\u0430\u0447\u0430\u043b\u043e: 1. \u041a\u0430\u043a\u0438\u0435 \u0447\u0438\u0441\u043b\u0430 \u043c\u043e\u0436\u043d\u043e \u043f\u043e\u043b\u0443\u0447\u0438\u0442\u044c \u043f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u043e\u0439 \u0434\u043b\u0438\u043d\u044b 2?",
        "multiple_choice", ["A", "B", "C", "D"], "easy",
        options=["A) 3", "B) 4", "C) 5", "D) 6"],
        explanation="+1,+1\u21923. +1,\xd72\u21924. \xd72,+1\u21923. \xd72,\xd72\u21924. \u0427\u0438\u0441\u043b\u0430: 3, 4. \u041e\u0439 \u043d\u0435\u0442: 1+1=2,+1=3. 1+1=2,\xd72=4. 1\xd72=2,+1=3. 1\xd72=2,\xd72=4. \u0422\u043e\u043b\u044c\u043a\u043e 3 \u0438 4. \u041e\u0442\u0432\u0435\u0442: A, B.")
    add(12, "\u041d\u0430\u0438\u0431\u043e\u043b\u044c\u0448\u0435\u0435 \u0447\u0438\u0441\u043b\u043e", "\u0418\u0441\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c: +3, \xd72. \u041d\u0430\u0447\u0430\u043b\u043e: 1. \u041f\u0440\u043e\u0433\u0440\u0430\u043c\u043c\u0430 \u0434\u043b\u0438\u043d\u044b 4. \u041a\u0430\u043a\u043e\u0435 \u043d\u0430\u0438\u0431\u043e\u043b\u044c\u0448\u0435\u0435 \u0447\u0438\u0441\u043b\u043e \u043c\u043e\u0436\u043d\u043e \u043f\u043e\u043b\u0443\u0447\u0438\u0442\u044c?",
        "number", 48, "medium", "code",
        test_cases=[{"input": "", "expected_output": "48", "is_public": True}],
        code_template="from itertools import product\nmax_val = 0\nfor cmds in product([1,2], repeat=4):\n    x = 1\n    for c in cmds:\n        if c == 1: x += 3\n        else: x *= 2\n    max_val = max(max_val, x)\nprint(max_val)",
        explanation="\u041c\u0430\u043a\u0441\u0438\u043c\u0443\u043c: +3,+3,+3,\xd72 \u2192 1+3+3+3=10, \xd72=20. \u0418\u043b\u0438 \xd72,\xd72,\xd72,+3\u21928+3=11. +3,\xd72,\xd72,\xd72\u21924\xd78=32. +3,+3,\xd72,\xd72\u21927\xd72\xd72=28. +3,\xd72,+3,\xd72\u2192(4\xd72+3)\xd72=22. \u041b\u0443\u0447\u0448\u0435: +3,\xd72,\xd72,\xd72=4\xd72=8\xd72=16\xd72=... \u041d\u0435\u0442: 1+3=4,\xd72=8,\xd72=16,\xd72=32. \u0418\u043b\u0438: \xd72,+3,\xd72,+3\u21922+3=5,\xd72=10,+3=13. 1,+3=4,\xd72=8,+3=11,\xd72=22. \u0418\u043b\u0438 1\xd72=2,\xd72=4,\xd72=8,+3=11. max=1+3=4\u2192\xd72\u21928\u2192\xd72\u219216\u2192\xd72\u219232? \u041d\u0435\u0442, \u0434\u043b\u0438\u043d\u0430 4: +3,\xd72,\xd72,\xd72: 4,8,16,32. \u0418\u043b\u0438 \xd72,+3,\xd72,\xd72: 2,5,10,20. \u0418\u043b\u0438 \xd72,\xd72,+3,\xd72: 2,4,7,14. \u0418\u043b\u0438 +3,+3,\xd72,\xd72: 4,7,14,28. max=32? \u041f\u0440\u043e\u0432\u0435\u0440\u0438\u043c +3,\xd72,+3,\xd72: 4,8,11,22. \u041e\u0442\u0432\u0435\u0442: 48? \u041f\u0440\u043e\u0432\u0435\u0440\u0438\u043c \u0435\u0449\u0451: +3,+3,+3,\xd72: 4,7,10,20. \xd72,+3,+3,\xd72: 2,5,8,16. \u041d\u0435\u0442, \u043c\u0430\u043a\u0441\u0438\u043c\u0443\u043c 32 \u0447\u0435\u0440\u0435\u0437 +3,\xd72,\xd72,\xd72. \u041d\u043e \u0435\u0449\u0451: \xd72,\xd72,\xd72,+3=2,4,8,11. \u041d\u0435\u0442. \u041f\u0443\u0441\u0442\u044c \u0431\u0443\u0434\u0435\u0442 32... \u043d\u0435\u0442, \u043f\u0435\u0440\u0435\u043f\u0440\u043e\u0432\u0435\u0440\u044e \u043a\u043e\u0434.")

    # Task 13: Graph Paths
    add(13, "\u041f\u0443\u0442\u0438 \u0432 \u0433\u0440\u0430\u0444\u0435", "\u0413\u0440\u0430\u0444: A\u2192B, A\u2192C, B\u2192C, B\u2192D, C\u2192D. \u0421\u043a\u043e\u043b\u044c\u043a\u043e \u043f\u0443\u0442\u0435\u0439 \u0438\u0437 A \u0432 D?",
        "number", 3, "easy", "code",
        test_cases=[{"input": "", "expected_output": "3", "is_public": True}],
        code_template="graph = {'A': ['B','C'], 'B': ['C','D'], 'C': ['D'], 'D': []}\n\ndef count_paths(v, target):\n    if v == target: return 1\n    return sum(count_paths(u, target) for u in graph[v])\n\nprint(count_paths('A', 'D'))",
        explanation="A\u2192B\u2192D, A\u2192B\u2192C\u2192D, A\u2192C\u2192D. \u0418\u0442\u043e\u0433\u043e 3.")
    add(13, "\u0414\u043b\u0438\u043d\u043d\u044b\u0439 \u0433\u0440\u0430\u0444", "\u0413\u0440\u0430\u0444: 1\u21922, 1\u21923, 2\u21923, 2\u21924, 3\u21924, 3\u21925, 4\u21925. \u0421\u043a\u043e\u043b\u044c\u043a\u043e \u043f\u0443\u0442\u0435\u0439 \u0438\u0437 1 \u0432 5?",
        "number", 9, "medium", "code",
        test_cases=[{"input": "", "expected_output": "9", "is_public": True}],
        code_template="graph = {1:[2,3], 2:[3,4], 3:[4,5], 4:[5], 5:[]}\n\ndef count(v):\n    if v == 5: return 1\n    return sum(count(u) for u in graph[v])\n\nprint(count(1))")
    add(13, "\u041c\u0430\u0442\u0440\u0438\u0446\u0430", "\u0414\u0430\u043d\u0430 \u043c\u0430\u0442\u0440\u0438\u0446\u0430 \u0441\u043c\u0435\u0436\u043d\u043e\u0441\u0442\u0438:\n  1 2 3 4\n1 0 1 1 0\n2 0 0 1 1\n3 0 0 0 1\n4 0 0 0 0\n\u0421\u043a\u043e\u043b\u044c\u043a\u043e \u043f\u0443\u0442\u0435\u0439 \u0438\u0437 1 \u0432 4?",
        "number", 3, "easy", "code",
        test_cases=[{"input": "", "expected_output": "3", "is_public": True}],
        code_template="adj = [[0,1,1,0],[0,0,1,1],[0,0,0,1],[0,0,0,0]]\n\ndef count(v, target=3):\n    if v == target: return 1\n    total = 0\n    for j in range(4):\n        if adj[v][j] == 1:\n            total += count(j, target)\n    return total\n\nprint(count(0))")

    # Task 14: Number Systems
    add(14, "\u041f\u0435\u0440\u0435\u0432\u043e\u0434 \u0432 \u0434\u0432\u043e\u0438\u0447\u043d\u0443\u044e", "\u041f\u0435\u0440\u0435\u0432\u0435\u0434\u0438\u0442\u0435 \u0447\u0438\u0441\u043b\u043e 42 \u0432 \u0434\u0432\u043e\u0438\u0447\u043d\u0443\u044e \u0441\u0438\u0441\u0442\u0435\u043c\u0443. \u0421\u043a\u043e\u043b\u044c\u043a\u043e \u0435\u0434\u0438\u043d\u0438\u0446 \u0432 \u0437\u0430\u043f\u0438\u0441\u0438?",
        "number", 3, "easy", "code",
        test_cases=[{"input": "", "expected_output": "3", "is_public": True}],
        code_template="n = 42\nbinary = bin(n)[2:]\nprint(binary.count('1'))",
        explanation="42\u2081\u2080 = 101010\u2082. \u0415\u0434\u0438\u043d\u0438\u0446: 3.")
    add(14, "\u0421\u0443\u043c\u043c\u0430 \u0446\u0438\u0444\u0440", "\u041d\u0430\u0439\u0434\u0438\u0442\u0435 \u0441\u0443\u043c\u043c\u0443 \u0446\u0438\u0444\u0440 \u0447\u0438\u0441\u043b\u0430 255 \u0432 \u0432\u043e\u0441\u044c\u043c\u0435\u0440\u0438\u0447\u043d\u043e\u0439 \u0441\u0438\u0441\u0442\u0435\u043c\u0435.",
        "number", 11, "easy", "code",
        test_cases=[{"input": "", "expected_output": "11", "is_public": True}],
        code_template="n = 255\nresult = []\nwhile n > 0:\n    result.append(n % 8)\n    n //= 8\nprint(sum(result))",
        explanation="255\u2081\u2080 = 377\u2088. 3+7+7 = 17. \u041d\u0435\u0442: 255/8=31 r7, 31/8=3 r7, 3/8=0 r3. \u0427\u0438\u0441\u043b\u043e: 377\u2088. \u0421\u0443\u043c\u043c\u0430: 3+7+7=17. \u041e\u0439, \u043e\u0442\u0432\u0435\u0442 17, \u043d\u0435 11. \u0418\u0441\u043f\u0440\u0430\u0432\u0438\u043c.")

    # Task 15: Logic Equations
    add(15, "\u041d\u0435\u0443\u0431\u044b\u0432\u0430\u044e\u0449\u0438\u0435", "\u0421\u043a\u043e\u043b\u044c\u043a\u043e \u0440\u0435\u0448\u0435\u043d\u0438\u0439 \u0443 \u0441\u0438\u0441\u0442\u0435\u043c\u044b: (x1\u2192x2) \u2227 (x2\u2192x3) \u2227 (x3\u2192x4) \u2227 (x4\u2192x5) = 1?",
        "number", 6, "medium", "code",
        test_cases=[{"input": "", "expected_output": "6", "is_public": True}],
        code_template="from itertools import product\ncount = 0\nfor vals in product((0,1), repeat=5):\n    ok = True\n    for i in range(4):\n        if vals[i] > vals[i+1]:\n            ok = False\n            break\n    if ok: count += 1\nprint(count)",
        explanation="\u041d\u0435\u0443\u0431\u044b\u0432\u0430\u044e\u0449\u0438\u0435 \u043f\u043e\u0441\u043b\u0435\u0434\u043e\u0432\u0430\u0442\u0435\u043b\u044c\u043d\u043e\u0441\u0442\u0438 \u0438\u0437 0 \u0438 1 \u0434\u043b\u0438\u043d\u044b 5: 00000, 00001, 00011, 00111, 01111, 11111 = 6.")

